module RefModule(clk, reset, in, out);
    input clk, reset, in;
    output out;
    reg unused_reg1, reg2;
    always @ (posedge clk)
        if (reset)
          begin
            unused_reg1 <= 0; reg2 <= 0;
          end
        else
          begin
            reg2 <= unused_reg1; unused_reg1 <= in;
          end
    assign out = {reg2,unused_reg1}==2'b01 ? 1 : 0;
endmodule
